const { ApolloServer, gql } = require('apollo-server');
const { User } = require('./models'); // Assuming you have a User model

// Define the GraphQL schema
const typeDefs = gql`
  type User {
    id: ID!
    name: String!
    email: String!
  }

  input UserIDInput {
    ids: [ID!]!
  }

  type Query {
    users(ids: UserIDInput!): [User]
  }
`;

// Define the resolvers
